export interface GameItem {
  instanceId: string;
  name: string;
  slot: EquipmentSlot;
  emoji: string;
  rarity: Rarity;
  ilvl: number;
  affixes: ItemAffix[];
  attackBonus: number;
  defenceBonus: number;
  hpBonus: number;
  critRating: number;
  source: 'smithed' | 'dropped';
  baseId?: string;
  maxSockets: number;
  socketedGems: string[];
  skills: ItemSkill[];
}

