   237→      const [updated] = await db.update(gameStates).set(result.updates).where(eq(gameStates.id, state.id)).returning();
   238→      return updated;
   239→    }
   240→
   241→    // ── Gathering ─────────────────────────────────────────────────────────────
   242→    const [skill, indexStr] = action.split("_");
   243→    const index = parseInt(indexStr);
   244→    const skillData = SKILLS_DATA[skill];
   245→    const data = skillData?.[index];
   246→    if (!data) return state;
   247→
   248→    const completions = Math.floor(elapsedSeconds / data.time);
   249→    if (completions <= 0) return state;
   250→
   251→    const xpKey = `${skill}Xp` as keyof GameState;
   252→    const resourceKey = `${data.prefix}_${index}` as keyof GameState;
   253→    const updates: Partial<GameState> = {
   254→      [xpKey]: (state[xpKey] as number) + completions * data.xp,
   255→      [resourceKey]: (state[resourceKey] as number) + completions,
   256→      actionUpdatedAt: new Date(new Date(state.actionUpdatedAt).getTime() + completions * data.time * 1000),
   257→    };
   258→
   259→    const [updated] = await db.update(gameStates).set(updates).where(eq(gameStates.id, state.id)).returning();
   260→    return updated;
   261→  }
   262→
   263→  async updateAction(action: string): Promise<GameState> {
   264→    const currentState = await this.getGameState();
   265→    const [updated] = await db.update(gameStates)
   266→      .set({ activeAction: action, actionUpdatedAt: new Date() })
   267→      .where(eq(gameStates.id, currentState.id)).returning();
   268→    return updated;
   269→  }
   270→
   271→  async equipItem(instanceId?: string, itemId?: string): Promise<GameState> {
   272→    const state = await this.getGameState();
   273→    const equipment = parseEquipment(state.equipment);
   274→    const craftItems = parseCraftItems(state.craftItems);
   275→    const lootBag = parseLootBag(state.lootBag);
   276→
   277→    let newItem: GameItem | null = null;
   278→
   279→    if (instanceId) {
   280→      const idx = lootBag.findIndex(i => i.instanceId === instanceId);
   281→      if (idx < 0) throw new Error("Item not found in loot bag");
   282→      newItem = lootBag[idx];
   283→      lootBag.splice(idx, 1);
   284→    } else if (itemId) {
   285→      if ((craftItems[itemId] ?? 0) < 1) throw new Error("Item not in inventory");
   286→      craftItems[itemId]--;
   287→      if (craftItems[itemId] <= 0) delete craftItems[itemId];
   288→      newItem = craftedToGameItem(itemId);
   289→      if (!newItem) throw new Error("Unknown item");
   290→    } else {
   291→      throw new Error("Must provide instanceId or itemId");
   292→    }
   293→
   294→    const prev = equipment[newItem.slot as EquipmentSlot] ?? null;
   295→    if (prev) {
   296→      if (prev.source === 'smithed' && prev.baseId) {
   297→        craftItems[prev.baseId] = (craftItems[prev.baseId] ?? 0) + 1;
   298→      } else {
   299→        lootBag.push(prev);
   300→      }
   301→    }
   302→
   303→    equipment[newItem.slot as EquipmentSlot] = newItem;
   304→
   305→    const [updated] = await db.update(gameStates).set({
   306→      equipment:  JSON.stringify(equipment),
   307→      craftItems: JSON.stringify(craftItems),
   308→      lootBag:    JSON.stringify(lootBag),
   309→    }).where(eq(gameStates.id, state.id)).returning();
   310→    return updated;
   311→  }
   312→
   313→  async unequipItem(slot: string): Promise<GameState> {
   314→    const state = await this.getGameState();
   315→    const equipment = parseEquipment(state.equipment);
   316→    const item = equipment[slot as EquipmentSlot] ?? null;
   317→    if (!item) throw new Error("Nothing equipped in that slot");
   318→
   319→    const craftItems = parseCraftItems(state.craftItems);
   320→    const lootBag = parseLootBag(state.lootBag);
   321→
   322→    if (item.source === 'smithed' && item.baseId) {
   323→      craftItems[item.baseId] = (craftItems[item.baseId] ?? 0) + 1;
   324→    } else {
   325→      lootBag.push(item);
   326→    }
   327→    delete equipment[slot as EquipmentSlot];
   328→
   329→    const [updated] = await db.update(gameStates).set({
   330→      equipment:  JSON.stringify(equipment),
   331→      craftItems: JSON.stringify(craftItems),
   332→      lootBag:    JSON.stringify(lootBag),
   333→    }).where(eq(gameStates.id, state.id)).returning();
   334→    return updated;
   335→  }
   336→
   337→  async destroyLoot(instanceId: string): Promise<GameState> {
   338→    const state = await this.getGameState();
   339→    const lootBag = parseLootBag(state.lootBag).filter(i => i.instanceId !== instanceId);
   340→    const [updated] = await db.update(gameStates)
   341→      .set({ lootBag: JSON.stringify(lootBag) })
   342→      .where(eq(gameStates.id, state.id)).returning();
   343→    return updated;
   344→  }
   345→}
   346→
   347→export const storage = new DatabaseStorage();
   348→

