   640→export function craftedToGameItem(itemId: string): GameItem | null {
   641→  const def = ALL_CRAFTABLE_ITEMS[itemId];
   642→  if (!def) return null;
   643→  const affix: ItemAffix[] = [];
   644→  if (def.attackBonus > 0)  affix.push({ type: 'strength', value: def.attackBonus });
   645→  if (def.defenceBonus > 0) affix.push({ type: 'armour',   value: def.defenceBonus });
   646→  if (def.hpBonus && def.hpBonus > 0) affix.push({ type: 'stamina', value: Math.round(def.hpBonus / 5) });
   647→  if (def.critRating && def.critRating > 0) affix.push({ type: 'agility', value: Math.round(def.critRating / 0.5) });
   648→  const rarity: Rarity = 'uncommon';
   649→  return {
   650→    instanceId: `crafted_${itemId}_${Date.now()}`,
   651→    name: def.name, slot: def.slot, emoji: def.emoji,
   652→    rarity, ilvl: def.ilvl, affixes: affix,
   653→    attackBonus: def.attackBonus, defenceBonus: def.defenceBonus,
   654→    hpBonus: def.hpBonus ?? 0, critRating: def.critRating ?? 0,
   655→    source: 'smithed', baseId: itemId,
   656→    maxSockets: rollSockets(rarity), socketedGems: [], skills: [],
   657→  };
   658→}
