   185→  { label: "Hunting",     prefix: "hide", emoji: "🪶", names: ["Rabbit","Bird","Fox","Wolf","Bear","Boar","Deer","Tiger","Dragon","Phoenix"] },
   186→  { label: "Crafting",    prefix: "item", emoji: "🧵", names: ["Cloth","Leather","Jewelry","Armor","Weapon","Artifact","Relic","Masterpiece","Celestial","Divine"] },
   187→];
   188→
   189→export default function Inventory() {
   190→  const { data: state } = useGameState();
   191→  const equipItem    = useEquipItem();
   192→  const unequipItem  = useUnequipItem();
   193→  const destroyLoot  = useDestroyLoot();
   194→  const { toast }    = useToast();
   195→
   196→  if (!state) return null;
   197→  const gs = state as GameState;
   198→
   199→  const equipment  = parseEquipment(gs.equipment);
   200→  const craftItems = parseCraftItems(gs.craftItems);
   201→  const lootBag    = parseLootBag(gs.lootBag);
   202→
   203→  const equipStats = getEquipmentStats(gs);
   204→
   205→  function handleEquipDropped(instanceId: string) {
   206→    equipItem.mutate({ instanceId }, {
   207→      onError: (err) => toast({ title: "Equip failed", description: err.message, variant: "destructive" }),
   208→    });
   209→  }
   210→  function handleEquipSmithed(itemId: string) {
   211→    equipItem.mutate({ itemId }, {
   212→      onError: (err) => toast({ title: "Equip failed", description: err.message, variant: "destructive" }),
   213→    });
   214→  }
   215→  function handleUnequip(slot: string) {
   216→    unequipItem.mutate(slot, {
   217→      onError: (err) => toast({ title: "Unequip failed", description: err.message, variant: "destructive" }),
   218→    });
   219→  }
   220→  function handleDestroy(instanceId: string) {
   221→    destroyLoot.mutate(instanceId, {
   222→      onError: (err) => toast({ title: "Failed", description: err.message, variant: "destructive" }),
   223→    });
   224→  }
   225→
   226→  const lootByRarity = [...lootBag].sort((a, b) => {
   227→    const order = { legendary: 0, epic: 1, rare: 2, uncommon: 3, common: 4 };
   228→    return order[a.rarity] - order[b.rarity];
   229→  });
   230→
   231→  return (
   232→    <div className="p-4 max-w-6xl mx-auto space-y-6">
   233→      <div>
   234→        <h1 className="text-xl font-bold flex items-center gap-2">
   235→          <Package className="w-5 h-5 text-yellow-400" /> Inventory
   236→        </h1>
   237→        <p className="text-sm text-muted-foreground">
   238→          {lootBag.length} item{lootBag.length !== 1 ? 's' : ''} in loot bag
   239→          {equipStats.critRating > 0 && ` · ${equipStats.critRating.toFixed(1)}% Crit`}
   240→          {equipStats.hpBonus > 0 && ` · +${equipStats.hpBonus} HP`}
   241→        </p>
   242→      </div>
   243→
   244→      {/* Loot + Gold */}
   245→      <div className="bg-card border border-border rounded-xl p-4">
   246→        <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-3">Loot</h2>
   247→        <div className="flex gap-6 text-sm">
   248→          <span>💰 <span className="font-bold text-yellow-400">{formatNumber(gs.gold)}</span> Gold</span>
   249→          <span>🦴 <span className="font-bold">{formatNumber(gs.bones)}</span> Bones</span>
   250→          {gs.dragonBones > 0 && <span>🐲 <span className="font-bold text-purple-400">{formatNumber(gs.dragonBones)}</span> Dragon Bones</span>}
   251→        </div>
   252→      </div>
   253→
   254→      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
   255→        {/* Character Equipment */}
   256→        <div className="bg-card border border-border rounded-xl p-4 space-y-3">
   257→          <div className="flex items-center gap-2 mb-1">
   258→            <Shield className="w-4 h-4 text-slate-400" />
   259→            <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Equipped</h2>
   260→          </div>
   261→
   262→          {/* Stat summary */}
   263→          {(equipStats.attackBonus > 0 || equipStats.defenceBonus > 0 || equipStats.hpBonus > 0 || equipStats.critRating > 0) && (
   264→            <div className="flex flex-wrap gap-x-4 gap-y-1 bg-muted/20 rounded-lg px-3 py-2 text-xs">
   265→              {equipStats.attackBonus > 0  && <span className="text-red-300">⚔ +{equipStats.attackBonus} ATK</span>}
   266→              {equipStats.defenceBonus > 0 && <span className="text-blue-300">🛡 +{equipStats.defenceBonus} DEF</span>}
   267→              {equipStats.hpBonus > 0      && <span className="text-green-300">❤ +{equipStats.hpBonus} HP</span>}
   268→              {equipStats.critRating > 0   && <span className="text-yellow-300">✦ +{equipStats.critRating.toFixed(1)}% Crit</span>}
   269→            </div>
   270→          )}
   271→
   272→          <div className="grid grid-cols-2 gap-2">
   273→            {ALL_SLOTS.map(slot => (
   274→              <EquipSlot
   275→                key={slot}
   276→                slot={slot}
   277→                item={(equipment[slot] as GameItem | undefined) ?? null}
   278→                onUnequip={() => handleUnequip(slot)}
   279→              />
   280→            ))}
   281→          </div>
   282→        </div>
   283→
   284→        {/* Loot Bag — dropped items */}
   285→        <div className="bg-card border border-border rounded-xl p-4 space-y-3">
   286→          <div className="flex items-center justify-between mb-1">
   287→            <div className="flex items-center gap-2">
   288→              <Sword className="w-4 h-4 text-yellow-400" />
   289→              <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
   290→                Loot Bag <span className="text-xs normal-case">({lootBag.length}/50)</span>
   291→              </h2>
   292→            </div>
   293→          </div>
   294→
   295→          {lootBag.length === 0 ? (
   296→            <div className="text-center py-8 text-muted-foreground">
   297→              <p className="text-sm">No items yet</p>
   298→              <p className="text-xs mt-1">Fight enemies to collect loot!</p>
   299→            </div>
   300→          ) : (
   301→            <div className="space-y-2 max-h-[400px] overflow-y-auto pr-1">
   302→              {lootByRarity.map(item => (
   303→                <ItemCard
   304→                  key={item.instanceId}
   305→                  item={item}
   306→                  onEquip={() => handleEquipDropped(item.instanceId)}
   307→                  onDestroy={() => handleDestroy(item.instanceId)}
   308→                />
   309→              ))}
   310→            </div>
   311→          )}
   312→        </div>
   313→      </div>
   314→
   315→      {/* Currently equipped items (as cards) */}
   316→      {Object.values(equipment).some(Boolean) && (
   317→        <div className="bg-card border border-border rounded-xl p-4 space-y-3">
   318→          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Equipped Items</h2>
   319→          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
   320→            {ALL_SLOTS.map(slot => {
   321→              const item = (equipment[slot] as GameItem | undefined) ?? null;
   322→              if (!item) return null;
   323→              return (
   324→                <ItemCard
   325→                  key={slot}
   326→                  item={item}
   327→                  isEquipped
   328→                  onUnequip={() => handleUnequip(slot)}
   329→                />
   330→              );
   331→            })}
   332→          </div>
   333→        </div>
   334→      )}
   335→
   336→      {/* Smithed items */}
   337→      {Object.keys(craftItems).length > 0 && (
   338→        <div className="bg-card border border-border rounded-xl p-4 space-y-3">
   339→          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Crafted Equipment</h2>
   340→          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
   341→            {Object.entries(craftItems).map(([itemId, qty]) => {
   342→              if (qty <= 0) return null;
   343→              const def = ALL_CRAFTABLE_ITEMS[itemId];
   344→              if (!def) return null;
   345→              return (
   346→                <div key={itemId} className="flex items-center gap-2 p-2 rounded-lg border border-green-500/30 bg-green-500/5"
   347→                  data-testid={`smithed-item-${itemId}`}>
   348→                  <span className="text-xl">{def.emoji}</span>
   349→                  <div className="flex-1 min-w-0">
   350→                    <p className="text-xs font-medium text-green-400 truncate">{def.name}</p>
   351→                    <p className="text-[10px] text-muted-foreground">x{qty} · ilvl {def.ilvl}</p>
   352→                  </div>
   353→                  <Button size="sm" className="h-7 text-xs px-2 flex-shrink-0"
   354→                    onClick={() => handleEquipSmithed(itemId)}
   355→                    disabled={equipItem.isPending}
   356→                    data-testid={`button-equip-smithed-${itemId}`}>
   357→                    Equip
   358→                  </Button>
   359→                </div>
   360→              );
   361→            })}
   362→          </div>
   363→        </div>
   364→      )}
   365→
   366→      {/* Resources */}
   367→      <div className="space-y-4">
   368→        <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Resources</h2>
   369→        {RESOURCE_SECTIONS.map(section => {
   370→          const items = Array.from({ length: 10 }, (_, i) => ({
   371→            name: section.names[i],
   372→            qty: ((gs as Record<string, unknown>)[`${section.prefix}_${i}`] as number) ?? 0,
   373→            key: `${section.prefix}_${i}`,
   374→          })).filter(it => it.qty > 0);
   375→
   376→          if (!items.length) return null;
   377→          return (
   378→            <div key={section.label} className="bg-card border border-border rounded-xl p-4">
   379→              <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">
   380→                {section.emoji} {section.label}
   381→              </h3>
   382→              <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-2">
   383→                {items.map(item => (
   384→                  <div key={item.key} className="bg-muted/20 rounded-lg p-2 text-center" data-testid={`resource-${item.key}`}>
   385→                    <p className="text-xs text-muted-foreground truncate">{item.name}</p>
   386→                    <p className="text-sm font-bold mt-0.5">{formatNumber(item.qty)}</p>
   387→                  </div>
   388→                ))}
   389→              </div>
   390→            </div>
   391→          );
   392→        })}
   393→      </div>
   394→    </div>
   395→  );
   396→}
