import { Link, useLocation } from "wouter";
import {
  Axe, Pickaxe, LayoutDashboard, Swords, Flame, Waves, PawPrint,
  Hammer, Shield, Package, Skull, Gem,
} from "lucide-react";
import { useGameState } from "@/hooks/use-game";
import { calculateLevel, getCombatLevel, formatNumber } from "@/lib/game-utils";
import type { GameState } from "@shared/schema";

const GATHERING_SKILLS = [
  { title: "伐木", url: "/woodcutting", icon: Axe,      xpKey: "woodcuttingXp" as const, color: "text-green-400"  },
  { title: "采矿", url: "/mining",      icon: Pickaxe,  xpKey: "miningXp"      as const, color: "text-yellow-400" },
  { title: "冶炼", url: "/smelting",    icon: Flame,    xpKey: "smeltingXp"    as const, color: "text-orange-400" },
  { title: "钓鱼", url: "/fishing",     icon: Waves,    xpKey: "fishingXp"     as const, color: "text-blue-400"   },
  { title: "狩猎", url: "/hunting",     icon: PawPrint, xpKey: "huntingXp"     as const, color: "text-red-400"    },
  { title: "制作", url: "/crafting",    icon: Hammer,   xpKey: "craftingXp"    as const, color: "text-purple-400" },
];

const PRODUCTION_SKILLS = [
  { title: "锻造",     url: "/smithing",      icon: Shield, xpKey: "smithingXp"       as const, color: "text-slate-400"  },
  { title: "皮革制作", url: "/leatherworking",icon: PawPrint,xpKey: "leatherworkingXp"as const, color: "text-amber-400"  },
  { title: "珠宝制作", url: "/jewelcrafting", icon: Gem,    xpKey: "jewelcraftingXp"  as const, color: "text-purple-400" },
];

function NavItem({ title, url, icon: Icon, color, level, isActive }: {
  title: string; url: string; icon: React.ElementType;
  color?: string; level: number | null; isActive: boolean;
}) {
  return (
    <Link href={url}>
      <div className={`flex items-center gap-2.5 px-3 py-2 mx-1 rounded cursor-pointer transition-colors ${
        isActive
          ? "bg-primary/20 text-primary border border-primary/30"
          : "text-muted-foreground hover:text-foreground hover:bg-accent"
      }`}>
        <Icon className={`w-4 h-4 flex-shrink-0 ${isActive ? "text-primary" : (color ?? "")}`} />
        <span className="text-sm font-medium flex-1 min-w-0 truncate">{title}</span>
        {level !== null && (
          <span className={`text-xs font-bold tabular-nums ${isActive ? "text-primary" : "text-muted-foreground"}`}>
            {level}
          </span>
        )}
      </div>
    </Link>
  );
}

function SectionLabel({ label }: { label: string }) {
  return (
    <div className="px-2 pt-3 pb-1">
      <span className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">{label}</span>
    </div>
  );
}

export function AppSidebar() {
  const [location] = useLocation();
  const { data: state } = useGameState();
  const gs = state as GameState | undefined;
  const combatLevel = gs ? getCombatLevel(gs) : null;

  return (
    <aside className="w-48 flex-shrink-0 bg-[hsl(220_13%_8%)] border-r border-border flex flex-col overflow-y-auto">
      <div className="px-3 py-4 border-b border-border">
        <div className="flex items-center gap-2">
          <Swords className="w-5 h-5 text-primary" />
          <span className="font-display font-bold text-base text-foreground">Idle RPG</span>
        </div>
        {gs && (
          <div className="mt-2 flex items-center gap-2 text-xs text-muted-foreground">
            <span>💰 {formatNumber(gs.gold)}</span>
            {gs.bones > 0 && <span>🦴 {formatNumber(gs.bones)}</span>}
          </div>
        )}
      </div>

      <nav className="flex-1 py-1">
        <SectionLabel label="常规" />
        <NavItem title="总览" url="/" icon={LayoutDashboard} level={null} isActive={location === "/"} />
        <NavItem title="背包" url="/inventory" icon={Package} level={null}
          isActive={location === "/inventory"} color="text-yellow-400" />

        <SectionLabel label="采集" />
        {GATHERING_SKILLS.map(skill => (
          <NavItem
            key={skill.title}
            title={skill.title}
            url={skill.url}
            icon={skill.icon}
            color={skill.color}
            level={gs ? calculateLevel(gs[skill.xpKey]) : null}
            isActive={location === skill.url}
          />
        ))}

        <SectionLabel label="战斗" />
        <NavItem title="战斗" url="/combat" icon={Skull}
          level={combatLevel} isActive={location === "/combat"} color="text-red-400" />

        <SectionLabel label="生产" />
        {PRODUCTION_SKILLS.map(skill => {
          const xp = gs ? ((gs as Record<string, unknown>)[skill.xpKey] as number | undefined) ?? 0 : null;
          return (
            <NavItem
              key={skill.title}
              title={skill.title}
              url={skill.url}
              icon={skill.icon}
              color={skill.color}
              level={xp !== null ? calculateLevel(xp) : null}
              isActive={location === skill.url}
            />
          );
        })}

        <SectionLabel label="物品" />
        <NavItem title="宝石" url="/gems" icon={Gem} level={null}
          isActive={location === "/gems"} color="text-cyan-400" />
      </nav>

      <div className="px-3 py-3 border-t border-border">
        <p className="text-[10px] text-muted-foreground text-center">Idle RPG v2.0</p>
      </div>
    </aside>
  );
}

import { useState, useEffect, useRef } from "react";
import { calculateLevel, levelProgress, xpForLevel, formatNumber } from "@/lib/game-utils";
import { useStartAction } from "@/hooks/use-game";
import type { GameState } from "@shared/schema";
import type { LucideIcon } from "lucide-react";

interface ResourceDef {
  name: string;
  emoji: string;
  time: number;
  xp: number;
  reqLevel: number;
  resourceKey: string;
  actionKey: string;
}

interface SkillPageProps {
  skillName: string;
  skillXp: number;
  icon: LucideIcon;
  iconColor: string;
  state: GameState;
  resources: ResourceDef[];
}

function ActiveProgressBar({
  resourceName,
  cycleTime,
  actionStartMs,
  onStop,
  isPending,
}: {
  resourceName: string;
  cycleTime: number;
  actionStartMs: number;
  onStop: () => void;
  isPending: boolean;
}) {
  const [progress, setProgress] = useState(0);
  const [timeLeft, setTimeLeft] = useState(cycleTime);
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    function tick() {
      const elapsed = (Date.now() - actionStartMs) / 1000;
      const cycleElapsed = elapsed % cycleTime;
      setProgress((cycleElapsed / cycleTime) * 100);
      setTimeLeft(Math.max(0, cycleTime - cycleElapsed));
      rafRef.current = requestAnimationFrame(tick);
    }

    rafRef.current = requestAnimationFrame(tick);
    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
    };
  }, [actionStartMs, cycleTime]);

  return (
    <div className="bg-[hsl(217_50%_10%)] border border-primary/30 rounded p-3 mb-4">
      <div className="flex items-center justify-between mb-2">
        <div>
          <span className="text-xs text-muted-foreground uppercase tracking-wider">当前进行中</span>
          <div className="text-sm font-semibold text-foreground">{resourceName}</div>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-xs text-muted-foreground tabular-nums w-10 text-right">
            {timeLeft.toFixed(1)}s
          </span>
          <button
            onClick={onStop}
            disabled={isPending}
            className="px-3 py-1 text-xs font-semibold bg-red-600 hover:bg-red-500 text-white rounded transition-colors disabled:opacity-50"
          >
            停止
          </button>
        </div>
      </div>
      <div className="h-4 bg-[hsl(220_13%_8%)] rounded overflow-hidden border border-border">
        <div
          className="h-full progress-bar-fill rounded"
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  );
}

export function SkillPage({ skillName, skillXp, icon: Icon, iconColor, state, resources }: SkillPageProps) {
  const { mutate: startAction, isPending } = useStartAction();
  const level = calculateLevel(skillXp);
  const progress = levelProgress(skillXp);
  const xpCurrent = xpForLevel(level);
  const xpNext = xpForLevel(level + 1);
  const xpInLevel = skillXp - xpCurrent;
  const xpNeeded = xpNext - xpCurrent;

  const isGlobalActive = state.activeAction !== "idle";
  const activeResource = resources.find((r) => state.activeAction === r.actionKey) ?? null;

  const actionStartMs = new Date(state.actionUpdatedAt as unknown as string).getTime();

  return (
    <div className="h-full flex flex-col">
      <div className="bg-[hsl(220_13%_10%)] border-b border-border px-4 py-3">
        <div className="flex items-center gap-3 mb-3">
