     1→import { useGameState, useStartAction } from "@/hooks/use-game";
     2→import { SMITHING_RECIPES, EQUIPMENT_ITEMS } from "@shared/game-data";
     3→import { calculateLevel, formatNumber, levelProgress } from "@/lib/game-utils";
     4→import type { GameState } from "@shared/schema";
     5→import { Button } from "@/components/ui/button";
     6→import { Progress } from "@/components/ui/progress";
     7→import { Shield, CheckCircle2 } from "lucide-react";
     8→import { useEffect, useRef, useState } from "react";
     9→
    10→function ActionTimer({ actionUpdatedAt, time }: { actionUpdatedAt: string; time: number }) {
    11→  const [progress, setProgress] = useState(0);
    12→  const rafRef = useRef<number>(0);
    13→  const startMs = new Date(actionUpdatedAt).getTime();
    14→
    15→  useEffect(() => {
    16→    const tick = () => {
    17→      const elapsed = (Date.now() - startMs) % (time * 1000);
    18→      setProgress((elapsed / (time * 1000)) * 100);
    19→      rafRef.current = requestAnimationFrame(tick);
    20→    };
    21→    rafRef.current = requestAnimationFrame(tick);
    22→    return () => cancelAnimationFrame(rafRef.current);
    23→  }, [startMs, time]);
    24→
    25→  return (
    26→    <div className="h-1.5 bg-muted/30 rounded-full overflow-hidden">
    27→      <div className="h-full bg-primary rounded-full transition-none" style={{ width: `${progress}%` }} />
    28→    </div>
    29→  );
    30→}
    31→
    32→export default function SmithingCraft() {
    33→  const { data: state } = useGameState();
    34→  const startAction = useStartAction();
    35→
    36→  if (!state) return null;
    37→  const gameState = state as GameState;
    38→  const smithingLevel = calculateLevel(gameState.smithingXp);
    39→  const smithingXp = gameState.smithingXp;
    40→
    41→  const activeAction = gameState.activeAction;
    42→  const isSmithing = activeAction.startsWith("smith_");
    43→  const activeIndex = isSmithing ? parseInt(activeAction.split("_")[1]) : -1;
    44→
    45→  function startRecipe(index: number) {
    46→    startAction.mutate(`smith_${index}`);
    47→  }
    48→
    49→  function stopSmithing() {
    50→    startAction.mutate("idle");
    51→  }
    52→
    53→  function getInputQty(resource: string): number {
    54→    return ((gameState as Record<string, unknown>)[resource] as number) ?? 0;
    55→  }
    56→
    57→  function canCraft(recipeIndex: number): boolean {
    58→    const recipe = SMITHING_RECIPES[recipeIndex];
    59→    if (!recipe) return false;
    60→    if (smithingLevel < recipe.reqLevel) return false;
    61→    return recipe.inputs.every(inp => getInputQty(inp.resource) >= inp.qty);
    62→  }
    63→
    64→  const BAR_NAMES = ["Bronze", "Iron", "Steel", "Silver", "Gold", "Mithril", "Adamant", "Rune", "Dragon", "Eternal"];
    65→
    66→  return (
    67→    <div className="p-4 max-w-4xl mx-auto space-y-5">
    68→      <div>
    69→        <h1 className="text-xl font-bold flex items-center gap-2">
    70→          <Shield className="w-5 h-5 text-slate-400" /> Smithing
    71→        </h1>
    72→        <p className="text-sm text-muted-foreground">Level {smithingLevel} · {formatNumber(smithingXp)} XP</p>
    73→        <Progress value={levelProgress(smithingXp)} className="mt-2 h-1.5" />
    74→      </div>
    75→
    76→      {/* Active smithing */}
    77→      {isSmithing && activeIndex >= 0 && (
    78→        <div className="bg-card border border-primary/30 rounded-xl p-4 space-y-3">
    79→          <div className="flex items-center justify-between">
    80→            <div className="flex items-center gap-2">
    81→              <div className="w-2 h-2 rounded-full bg-primary animate-pulse" />
    82→              <span className="font-medium text-primary">
    83→                Smithing {EQUIPMENT_ITEMS[SMITHING_RECIPES[activeIndex]?.output]?.name ?? "..."}
    84→              </span>
    85→            </div>
    86→            <Button variant="outline" size="sm" onClick={stopSmithing} data-testid="button-stop-smithing">Stop</Button>
    87→          </div>
    88→          <ActionTimer actionUpdatedAt={gameState.actionUpdatedAt as unknown as string} time={SMITHING_RECIPES[activeIndex]?.time ?? 8} />
    89→        </div>
    90→      )}
    91→
    92→      {/* Recipe list */}
    93→      <div className="space-y-2">
    94→        <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Recipes</h2>
    95→        {SMITHING_RECIPES.map((recipe, index) => {
    96→          const item = EQUIPMENT_ITEMS[recipe.output];
    97→          if (!item) return null;
    98→          const unlocked = smithingLevel >= recipe.reqLevel;
    99→          const hasResources = canCraft(index);
   100→          const isActive = activeIndex === index;
   101→
   102→          return (
   103→            <div key={recipe.id}
   104→              className={`flex items-center gap-3 p-3 rounded-lg border transition-colors ${
   105→                !unlocked ? "border-border bg-muted/10 opacity-50" :
   106→                isActive ? "border-primary/50 bg-primary/10" :
   107→                "border-border bg-card hover:border-primary/30"
   108→              }`}
   109→              data-testid={`recipe-${recipe.id}`}>
   110→
   111→              <span className="text-2xl">{item.emoji}</span>
   112→
   113→              <div className="flex-1 min-w-0">
   114→                <div className="flex items-center gap-2">
   115→                  <span className="font-medium text-sm">{item.name}</span>
   116→                  {isActive && <span className="text-xs text-primary font-medium">Crafting...</span>}
   117→                  {hasResources && !isActive && unlocked && (
   118→                    <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />
   119→                  )}
   120→                </div>
   121→                <div className="flex flex-wrap gap-x-3 gap-y-0.5 mt-0.5 text-xs text-muted-foreground">
   122→                  {recipe.inputs.map(inp => {
   123→                    const have = getInputQty(inp.resource);
   124→                    const barIdx = parseInt(inp.resource.split("_")[1]);
   125→                    const barName = BAR_NAMES[barIdx] ?? inp.resource;
   126→                    const ok = have >= inp.qty;
   127→                    return (
   128→                      <span key={inp.resource} className={ok ? "text-green-400" : "text-red-400"}>
   129→                        {barName} Bar x{inp.qty} ({have} owned)
   130→                      </span>
   131→                    );
   132→                  })}
   133→                  <span>· {recipe.xp} XP · {recipe.time}s</span>
   134→                  {item.attackBonus > 0 && <span className="text-red-300">ATK +{item.attackBonus}</span>}
   135→                  {item.defenceBonus > 0 && <span className="text-blue-300">DEF +{item.defenceBonus}</span>}
   136→                </div>
   137→                {!unlocked && (
   138→                  <p className="text-xs text-muted-foreground mt-0.5">Requires Smithing level {recipe.reqLevel}</p>
   139→                )}
   140→              </div>
   141→
   142→              <div className="flex-shrink-0">
   143→                {isActive ? (
   144→                  <Button size="sm" variant="outline" onClick={stopSmithing} data-testid={`button-stop-${recipe.id}`}>Stop</Button>
   145→                ) : (
   146→                  <Button size="sm" disabled={!unlocked || !hasResources || startAction.isPending}
   147→                    onClick={() => startRecipe(index)} data-testid={`button-craft-${recipe.id}`}>
   148→                    {!unlocked ? `Lv ${recipe.reqLevel}` : "Craft"}
   149→                  </Button>
   150→                )}
   151→              </div>
   152→            </div>
   153→          );
   154→        })}
   155→      </div>
   156→    </div>
   157→  );
   158→}
