// ─── Gem stat preview ─────────────────────────────────────────────────────────
function GemStatLine({ gemKey }: { gemKey: string }) {
  const b = getGemBonus(gemKey);
  return (
    <span className="text-xs text-muted-foreground">
      {b.attackBonus  > 0 && <span className="text-red-300">⚔+{b.attackBonus} </span>}
