   185→const SKILL_POOL: { type: SkillType; name: string; minVal: number; maxVal: number; desc: (v: number) => string }[] = [
   186→  { type: 'lifesteal',   name: '吸血',   minVal: 3,  maxVal: 15, desc: v => `击中时吸取 ${v}% 伤害恢复生命` },
