   195→
   196→const RARITY_SKILL_COUNT: Record<Rarity, number> = {
   197→  common: 0, uncommon: 0, rare: 1, epic: 2, legendary: 3,
   198→};
   199→const RARITY_MAX_SOCKETS: Record<Rarity, number> = {
   200→  common: 0, uncommon: 1, rare: 2, epic: 3, legendary: 4,
   201→};
   202→
   203→function rollSkills(rarity: Rarity): ItemSkill[] {
   204→  const count = RARITY_SKILL_COUNT[rarity];
   205→  if (count === 0) return [];
   206→  const pool = [...SKILL_POOL];
   207→  const result: ItemSkill[] = [];
   208→  const used = new Set<SkillType>();
   209→  for (let i = 0; i < count; i++) {
   210→    const avail = pool.filter(s => !used.has(s.type));
   211→    if (!avail.length) break;
   212→    const s = avail[Math.floor(Math.random() * avail.length)];
   213→    used.add(s.type);
   214→    const value = Math.round(s.minVal + Math.random() * (s.maxVal - s.minVal));
   215→    result.push({ type: s.type, name: s.name, value, description: s.desc(value) });
   216→  }
   217→  return result;
   218→}
   219→
   220→function rollSockets(rarity: Rarity): number {
   221→  const max = RARITY_MAX_SOCKETS[rarity];
   222→  if (max === 0) return 0;
   223→  if (rarity === 'uncommon') return Math.random() < 0.5 ? 1 : 0;
   224→  if (rarity === 'rare') return 1 + Math.floor(Math.random() * 2);     // 1-2
   225→  if (rarity === 'epic') return 2 + Math.floor(Math.random() * 2);     // 2-3
   226→  return max; // legendary always max
   227→}
