   252→export function getEquipmentBonuses(equipment: EquipmentState) {
   253→  let attackBonus = 0, defenceBonus = 0, hpBonus = 0, critRating = 0;
   254→  for (const item of Object.values(equipment)) {
   255→    if (!item) continue;
   256→    attackBonus  += item.attackBonus;
   257→    defenceBonus += item.defenceBonus;
   258→    hpBonus      += item.hpBonus;
   259→    critRating   += item.critRating;
   260→  }
   261→  return { attackBonus, defenceBonus, hpBonus, critRating };
   262→}
