   305→export function smithedToGameItem(itemId: string): GameItem | null {
   306→  const def = EQUIPMENT_ITEMS[itemId];
   307→  if (!def) return null;
   308→  const affix: ItemAffix[] = [];
   309→  if (def.attackBonus > 0)  affix.push({ type: 'strength', value: def.attackBonus });
   310→  if (def.defenceBonus > 0) affix.push({ type: 'armour',   value: def.defenceBonus });
   311→  if (def.hpBonus && def.hpBonus > 0) affix.push({ type: 'stamina', value: Math.round(def.hpBonus / 5) });
   312→  if (def.critRating && def.critRating > 0) affix.push({ type: 'agility', value: Math.round(def.critRating / 0.5) });
   313→  return {
   314→    instanceId: `smithed_${itemId}_${Date.now()}`,
   315→    name: def.name, slot: def.slot, emoji: def.emoji,
   316→    rarity: 'uncommon', ilvl: def.ilvl, affixes: affix,
   317→    attackBonus: def.attackBonus, defenceBonus: def.defenceBonus,
   318→    hpBonus: def.hpBonus ?? 0, critRating: def.critRating ?? 0,
   319→    source: 'smithed', baseId: itemId,
   320→    maxSockets: rollSockets('uncommon'), socketedGems: [], skills: [],
   321→  };
   322→}
