// Slot-biased affix pools (Diablo-style slot affinity)
const SLOT_AFFIX_POOL: Record<EquipmentSlot, AffixType[]> = {
  weapon:  ['strength', 'strength', 'agility', 'enhanced_damage', 'enhanced_damage', 'crushing_blow', 'agility', 'stamina'],
