    61→function getPlayerAttack(state: GameState): number {
    62→  const equipment = parseEquipment(state.equipment);
    63→  const { attackBonus, critRating } = getEquipmentBonuses(equipment);
    64→  const baseAtk = Math.max(1, Math.floor(calcLevel(state.attackXp) * 1.2) + attackBonus);
    65→  const critMult = 1 + (critRating / 100) * 0.5;
    66→  return Math.floor(baseAtk * critMult);
