    79→// Roll gems from a pool using expected-value distribution
    80→function rollGemDropsFromPool(completions: number, chance: number, pool: string[]): Record<string, number> {
    81→  const expected = completions * chance;
    82→  const total = Math.floor(expected) + (Math.random() < (expected % 1) ? 1 : 0);
    83→  const gems: Record<string, number> = {};
    84→  for (let i = 0; i < total; i++) {
    85→    const key = pool[Math.floor(Math.random() * pool.length)];
    86→    gems[key] = (gems[key] ?? 0) + 1;
    87→  }
    88→  return gems;
    89→}
