   102→  xpKey: keyof GameState,
   103→  now: Date,
   104→): Promise<{ updates: Partial<GameState>; updated?: GameState } | null> {
   105→  const recipe = recipes[recipeIndex];
   106→  if (!recipe) return null;
   107→
   108→  const elapsedSeconds = (now.getTime() - new Date(state.actionUpdatedAt).getTime()) / 1000;
   109→  const ticks = Math.floor(elapsedSeconds / recipe.time);
   110→  if (ticks <= 0) return null;
   111→
   112→  const craftItems = parseCraftItems(state.craftItems);
   113→  const tempRes: Record<string, number> = {};
   114→  for (const inp of recipe.inputs) tempRes[inp.resource] = ((state as Record<string, unknown>)[inp.resource] as number) ?? 0;
   115→
   116→  let actualTicks = 0;
   117→  for (let i = 0; i < ticks; i++) {
   118→    if (!recipe.inputs.every(inp => (tempRes[inp.resource] ?? 0) >= inp.qty)) break;
   119→    for (const inp of recipe.inputs) tempRes[inp.resource] -= inp.qty;
   120→    craftItems[recipe.output] = (craftItems[recipe.output] ?? 0) + 1;
   121→    actualTicks++;
   122→  }
   123→
   124→  const updates: Partial<GameState> = {
   125→    [xpKey]: (state[xpKey] as number) + actualTicks * recipe.xp,
   126→    craftItems: JSON.stringify(craftItems),
   127→    actionUpdatedAt: new Date(new Date(state.actionUpdatedAt).getTime() + actualTicks * recipe.time * 1000),
   128→  };
   129→  for (const inp of recipe.inputs) (updates as Record<string, unknown>)[inp.resource] = tempRes[inp.resource];
   130→  if (actualTicks === 0 || actualTicks < ticks) updates.activeAction = "idle";
   131→
   132→  return { updates };
   133→}
