// ─── Storage interface ─────────────────────────────────────────────────────────
export interface IStorage {
  getGameState(): Promise<GameState>;
  updateAction(action: string): Promise<GameState>;
  equipItem(instanceId?: string, itemId?: string): Promise<GameState>;
  unequipItem(slot: string): Promise<GameState>;
