// ─── Helpers ───────────────────────────────────────────────────────────────────
function calcLevel(xp: number): number { return Math.floor(Math.sqrt(Math.max(0, xp))) + 1; }

function parseEquipment(raw: string): EquipmentState {
  try { return JSON.parse(raw) as EquipmentState; } catch { return {}; }
